const results = [];
const items = $input.all();

for (const item of items) {
  const data = item.json;
  const elements = Array.isArray(data) ? data : (data.elements || [data]);

  for (const element of elements) {
    // 1. Handle Member Snapshot Data structure (which contains snapshotData array)
    if (element.snapshotData && Array.isArray(element.snapshotData)) {
      for (const post of element.snapshotData) {
        const shareLink = post.ShareLink || '';
        let id = '';
        const decoded = decodeURIComponent(shareLink);
        const match = decoded.match(/(urn:li:[a-zA-Z0-9_]+:[0-9]+)/);
        if (match) {
          id = match[1];
        } else {
          id = shareLink || Math.random().toString();
        }

        const content = post.ShareCommentary || '';
        const url = shareLink;
        const published_at = post.Date ? new Date(post.Date).toISOString() : new Date().toISOString();
        const author = 'me';

        results.push({
          id: id.toString(),
          author,
          content,
          url,
          published_at,
          processed: 0
        });
      }
      continue;
    }

    // 2. Handle original Changelog / direct structure
    const activity = element.activity || {};
    const author = activity.author || element.actor || '';
    const id = element.resourceId || element.id || '';
    if (!id) continue;

    let content = '';
    if (activity.specificContent && activity.specificContent['com.linkedin.ugc.ShareContent']) {
      const shareContent = activity.specificContent['com.linkedin.ugc.ShareContent'];
      if (shareContent.shareCommentary) {
        content = shareContent.shareCommentary.text || '';
      }
    } else if (activity.specificContent && activity.specificContent['com.linkedin.share.ShareContent']) {
      const shareContent = activity.specificContent['com.linkedin.share.ShareContent'];
      if (shareContent.shareCommentary) {
        content = shareContent.shareCommentary.text || '';
      }
    }

    const published_at_ms = (activity.created && activity.created.time) || activity.firstPublishedAt || element.processedAt || element.capturedAt;
    const published_at = published_at_ms ? new Date(published_at_ms).toISOString() : new Date().toISOString();
    const url = element.resourceUri ? `https://www.linkedin.com${element.resourceUri}` : '';

    results.push({
      id: id.toString(),
      author,
      content,
      url,
      published_at,
      processed: 0
    });
  }
}
return results;

const results = [];
const items = $input.all();

for (const item of items) {
  const data = item.json;
  const elements = Array.isArray(data) ? data : (data.elements || [data]);

  for (const element of elements) {
    // 1. Handle Member Snapshot Data structure
    if (element.snapshotData && Array.isArray(element.snapshotData)) {
      for (const action of element.snapshotData) {
        const resourceName = action.resourceName || '';
        const resourceUri = action.resourceUri || '';
        const activity = action.activity || {};

        let action_type = '';
        let post_id = '';
        let id = action.resourceId || action.id || '';
        let content = '';

        if (resourceName.includes('comments') || resourceUri.includes('comments')) {
          action_type = 'comment';
          content = (activity.message && activity.message.text) || '';
          post_id = activity.object || '';
          if (!post_id && resourceUri) {
            const postMatch = resourceUri.match(/\/socialActions\/([^/]+)/);
            if (postMatch) post_id = postMatch[1];
          }
        } else if (resourceName.includes('likes') || resourceUri.includes('likes')) {
          action_type = 'like';
          post_id = activity.object || '';
          if (!post_id && resourceUri) {
            const postMatch = resourceUri.match(/\/socialActions\/([^/]+)/);
            if (postMatch) post_id = postMatch[1];
          }
          if (!id) {
            id = `${post_id}_like_${activity.actor || 'me'}`;
          }
        } else {
          continue;
        }

        if (post_id) {
          const urnMatch = decodeURIComponent(post_id).match(/(urn:li:[a-zA-Z0-9_]+:[0-9]+)/);
          if (urnMatch) post_id = urnMatch[1];
        }

        const published_at_ms = (activity.created && activity.created.time) || action.processedAt || action.capturedAt;
        const published_at = published_at_ms ? new Date(published_at_ms).toISOString() : new Date().toISOString();
        const author = activity.actor || action.actor || 'me';

        results.push({
          id: id.toString(),
          post_id: post_id || 'unknown',
          action_type,
          author,
          content,
          published_at,
          processed: 0
        });
      }
      continue;
    }

    // 2. Direct/Changelog structure
    const resourceName = element.resourceName || '';
    const resourceUri = element.resourceUri || '';
    const activity = element.activity || {};

    let action_type = '';
    let post_id = '';
    let id = element.resourceId || element.id || '';
    let content = '';

    if (resourceName.includes('comments') || resourceUri.includes('comments')) {
      action_type = 'comment';
      content = (activity.message && activity.message.text) || '';
      post_id = activity.object || '';
      if (!post_id && resourceUri) {
        const postMatch = resourceUri.match(/\/socialActions\/([^/]+)/);
        if (postMatch) post_id = postMatch[1];
      }
    } else if (resourceName.includes('likes') || resourceUri.includes('likes')) {
      action_type = 'like';
      post_id = activity.object || '';
      if (!post_id && resourceUri) {
        const postMatch = resourceUri.match(/\/socialActions\/([^/]+)/);
        if (postMatch) post_id = postMatch[1];
      }
      if (!id) {
        id = `${post_id}_like_${activity.actor || 'me'}`;
      }
    } else {
      continue;
    }

    if (post_id) {
      const urnMatch = decodeURIComponent(post_id).match(/(urn:li:[a-zA-Z0-9_]+:[0-9]+)/);
      if (urnMatch) post_id = urnMatch[1];
    }

    const published_at_ms = (activity.created && activity.created.time) || element.processedAt || element.capturedAt;
    const published_at = published_at_ms ? new Date(published_at_ms).toISOString() : new Date().toISOString();
    const author = activity.actor || element.actor || 'me';

    results.push({
      id: id.toString(),
      post_id: post_id || 'unknown',
      action_type,
      author,
      content,
      published_at,
      processed: 0
    });
  }
}
return results;
